import{c as e,Q as t,j as r,m as i}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"Local-first safety","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/local-first-safety.md","filePath":"concepts/local-first-safety.md","lastUpdated":null}'),o={name:"concepts/local-first-safety.md"};function s(l,a,n,d,c,p){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="local-first-safety" tabindex="-1">Local-first safety <a class="header-anchor" href="#local-first-safety" aria-label="Permalink to &quot;Local-first safety&quot;">​</a></h1><p>Audience: all users<br> Goal: show what each workflow can modify<br> Type: explanation</p><p>The project is designed around local files and explicit write boundaries. Your audio is not uploaded by the app.</p><h2 id="normal-read-only-audio-workflows" tabindex="-1">Normal read-only audio workflows <a class="header-anchor" href="#normal-read-only-audio-workflows" aria-label="Permalink to &quot;Normal read-only audio workflows&quot;">​</a></h2><p>These workflows may read audio files and write SQLite state, but they do not rewrite source audio:</p><ul><li>scanning tags into the library database;</li><li>refreshing tag metadata;</li><li>SONARA, MAEST, MERT, CLAP, and classifier analysis;</li><li>browsing and preview playback;</li><li>seed search, text search, SONARA search, and SET previews;</li><li>reset and clear actions for database analysis state;</li><li>playlist/report export.</li></ul><p>Browser preview may transcode AIFF/AIF to WAV for streaming. That is a read-only media response, not a rewrite of the source file.</p><h2 id="what-writes-sqlite" tabindex="-1">What writes SQLite <a class="header-anchor" href="#what-writes-sqlite" aria-label="Permalink to &quot;What writes SQLite&quot;">​</a></h2><p>The main app stores library rows, metadata, analysis results, embeddings, search-related state, likes, and classifier scores in SQLite. Writes are routed through the project database layer with a path-scoped lock.</p><h2 id="what-writes-reports" tabindex="-1">What writes reports <a class="header-anchor" href="#what-writes-reports" aria-label="Permalink to &quot;What writes reports&quot;">​</a></h2><p>Exports, duplicate reports, and audio repair reports write local files under the selected output directory. Reports are separate from source audio.</p><h2 id="what-can-write-audio-tags" tabindex="-1">What can write audio tags <a class="header-anchor" href="#what-can-write-audio-tags" aria-label="Permalink to &quot;What can write audio tags&quot;">​</a></h2><p>The explicit standard-genre write workflow can write stored MAEST genre labels to standard audio genre tags. It is not part of normal analysis or search.</p><h2 id="what-can-delete-audio" tabindex="-1">What can delete audio <a class="header-anchor" href="#what-can-delete-audio" aria-label="Permalink to &quot;What can delete audio&quot;">​</a></h2><p>Only duplicate cleanup apply mode is intended to delete audio files, and only after an explicit apply workflow and confirmation. Routine verification and tests should not run destructive apply mode.</p>',15)])])}const f=e(o,[["render",s]]);export{u as __pageData,f as default};
